using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        // Map Student Name -> Score
        Dictionary<string, int> grades = new Dictionary<string, int>();

        grades.Add("Alice", 95);
        grades.Add("Bob", 82);
        grades["Charlie"] = 78;

        Console.WriteLine("--- Grades ---");

        // Update a score
        grades["Bob"] = 85;

        foreach(var student in grades) {
            Console.WriteLine($"{student.Key}: {student.Value}");
        }

        // Calculate Average
        int total = 0;
        foreach(int score in grades.Values) {
            total += score;
        }

        double avg = (double)total / grades.Count;
        Console.WriteLine($"\nAverage Class Score: {avg:F2}");
    }
}
